"use strict";(self.webpackChunkhalt_website=self.webpackChunkhalt_website||[]).push([[38330],{19821:e=>{e.exports=JSON.parse('{"tag":{"label":"heart","permalink":"/docs/tags/heart","allTagsPath":"/docs/tags","count":1,"items":[{"id":"guinea-pigs/illnesses-and-conditions/fetal-arrhythmia","title":"Fetal Arrhythmia in Guinea Pigs: What It Is and What It Means","description":"Pregnancy in guinea pigs can be a delicate time, requiring close monitoring and appropriate veterinary care. One rare but important condition that can arise is fetal arrhythmia, an irregular heartbeat detected in a developing fetus. While unsettling to hear about, understanding this condition can help owners and rescues make informed decisions.","permalink":"/docs/guinea-pigs/illnesses-and-conditions/fetal-arrhythmia"}],"unlisted":false}}')}}]);